import subprocess
import sys

def check_gemini_cli_version():
    try:
        result = subprocess.run(
            ["gemini", "--version"],
            capture_output=True,
            text=True,
            check=True
        )
        print(f"Gemini CLI is installed. Version: {result.stdout.strip()}")
    except subprocess.CalledProcessError:
        print("Gemini CLI is not installed or the command is not found.")
    except FileNotFoundError:
        print("Gemini CLI executable not found in PATH.")

if __name__ == "__main__":
    check_gemini_cli_version()
